module LIFObuffer (
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

reg [3:0] stack_mem [0:3];
reg [2:0] SP;

always @(posedge Clk) begin
    if (Rst) begin
        SP <= 3;
        EMPTY <= 1;
        FULL <= 0;
        stack_mem[0] <= 0;
        stack_mem[1] <= 0;
        stack_mem[2] <= 0;
        stack_mem[3] <= 0;
    end else if (EN) begin
        if (!RW && !FULL) begin
            stack_mem[SP] <= dataIn;
            SP <= SP - 1;
            if (SP == 0)
                EMPTY <= 1;
            FULL <= (SP == 3);
        end else if (RW && !EMPTY) begin
            dataOut <= stack_mem[SP];
            stack_mem[SP] <= 0;
            SP <= SP + 1;
            EMPTY <= (SP == 3);
            FULL <= 0;
        end
    end
end

endmodule
